import express from "express";
import cors from "cors";
import cookieParser from "cookie-parser";

const app = express();

//basic configuration
//app.use basically means apply this rule to every incoming request..so..
app.use(express.json({ limit: "16kb" })); //this will tell the server tha data came in req body can be json data so server interprets it...
app.use(express.urlencoded({ extended: true, limit: "16kb" })); //as example html forms usually doesnt send json data it sends somethind url encoded...for that..this..
app.use(express.static("public"));

//cookie-parser
app.use(cookieParser());

//cors configuration...
(app.use(
  cors({
    origin: process.env.CORS_ORIGIN?.split(",") || "http://localhost:5173",
    credentials: true,
    methods: ["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"],
    allowedHeaders: ["Authorization", "Content-Type"],
  }),
),
  app.get("/", (req, res) => {
    res.send("Welcome to basecamp");
  })
);

// import the routes
import  healthCheckRouter  from "./routes/healthcheck.routes.js";
app.use("/api/v1/healthcheck", healthCheckRouter);

    //testing mail...
import testRoutes from "./routes/test.routes.js";
app.use("/api", testRoutes);

    //auth router
import authRouter from "./routes/auth.routes.js";
app.use("/api/v1/auth", authRouter);

export default app;

