import { User } from "../models/user.models.js"
import { ApiResponse } from "../utils/api-response.js"
import { ApiError } from "../utils/api-error.js"
import { asyncHandler } from "../utils/async-handler.js"
import { emailVerifcationMailGenContent, forgotPasswordMailGenContent, sendEmail } from "../utils/mail.js"
import jwt from "jsonwebtoken"
import { application } from "express"

//we are making new function for saving access and refresh token.
const generateAccessAndRefreshTokens = async (userId) => {
    try {
        const user = await User.findById(userId);
        const accessToken = user.generateAccessToken();
        const refreshToken = user.generateRefreshToken();

        //update and save in database.
        user.refreshToken = refreshToken;
        await user.save({validateBeforeSave: false});
        return {accessToken , refreshToken};

    } catch (error) {
        throw new ApiError(500 , "Something went wrong while generating the access token") 
    }

}

const registerUser = asyncHandler(async (req,res) => {
    const {email,username,password,role} = req.body

    //check in db if user alreday exists
    const existedUser = await User.findOne({
        $or: [{username} ,{email}]//this is will check if any of this is found in DB then we will make it true,
    })

    if(existedUser){
        throw new ApiError(409, "User with email or username already exists", []);
    }

    const user = await User.create({
        // the object keys you pass to Mongoose must match the schema field names.
        //automatically saved using create..
        email,
        password,
        username,
        isEmailVerified: false
        //these are sent from the req body
    })

    const { unHashedToken , hashedToken , tokenExpiry } = user.generateTemporaryToken()
    user.emailVerificationToken = hashedToken
    user.emailVerificationExpiry = tokenExpiry

    await user.save({validateBeforeSave: false})

    //now send the email.
    await sendEmail(
        {
            email: user?.email,
            subject: "Please verify your email.",
            mailGenContent: emailVerifcationMailGenContent(
                user.username,
                `${req.protocol}://${req.get("host")}/api/v1/users/verify-email/${unHashedToken}`
            )
        }
    )

    const createUser = await User.findById(user._id).select(
        "-password -refreshToken -emailVerificationToken -emailVerificationExpiry"
    );

    if(!createUser){
        throw new ApiError(500 , "Something went wrong while registering a user")

    }

    return res
        .status(201)
        .json(
            new ApiResponse(
                200,
                {user : createUser},
                "User registered successfully"
            )
        )
})

const login = asyncHandler(async(req,res) => {
     const {email , password , username} = req.body

     if(!email){
        throw new ApiError(400 , "email is required");
     }

    const user = await User.findOne({email})

    if(!user){
        throw new ApiError(400 , "User does not exist")
    }

    const isPasswordvalid = await user.isPasswordCorrect(password)

    if(!isPasswordvalid){
        throw new ApiError(400, "Invalid credentials")
    }

    const {accessToken , refreshToken } = await generateAccessAndRefreshTokens(user._id)


    const loggedInuser = await User.findById(user._id).select(
        "-password -refreshToken -emailVerificationToken -emailVerificationExpiry"
    );

    const options = {
        httpOnly : true,
        secure : true
    }

    return res
        .status(200)
        .cookie("accessToken", accessToken , options)
        .cookie("refreshToken", refreshToken , options)//not everytime..
        .json(
            new ApiResponse(
                200,
                {
                    user: loggedInuser,
                    accessToken,
                    refreshToken
                },
                "User logged in successfully"
            )
        )

})

const logoutUser = asyncHandler(async(req,res) => {
    await User.findByIdAndUpdate(
        req.user._id,
        {
            $set:{
                refreshToken: ""
            }
        },
        {
            new:true
        },

    );

    const options = {
        httpOnly: true,
        secure: true
    }

    return res
        .status(200)
        .clearCookie("accessToken" , options)
        .clearCookie("refreshToken" , options)
        .json(
            new ApiResponse(200 , {} , "User LoggedOut")
        )
})

const getCurrentUser = asyncHandler(async (req , res) => {
    return res  
        .status(200)
        .json(
            new ApiResponse(
                200,
                req.user,
                "Current user fetched successfully"
            )
        )
});

const verifyEmail = asyncHandler(async (req , res) => {
    const {verificationToken} = req.params

    if(!verificationToken){
        throw new ApiError(400 , "Email verification token is missing!")
    }

    let hashedToken = crypto.createHash("sha256").update(verificationToken).digest("hex")

    const user = await User.findOne({
         emailVerificationToken: hashedToken,
         emailVerificationExpiry: {$gt: Date.now()}
    })

    if(!user){
        throw new ApiError(400, "Token is invalid or expired")
    }

    user.emailVerificationToken = undefined
    user.emailVerificationExpiry = undefined

    user.isEmailVerified = true
    await user.save({validateBeforeSave:false})

    return res
        .status(200)
        .json(
            new ApiResponse(
                200,
                {
                    isEmailVerified: true
                },
                "Email is verified"
            )
        )

})

const resendEmailVerification = asyncHandler(async (req , res) => {
    const user = await User.findById(req.user?._id)

    if(!user){
        throw new ApiError(404 , "User does not exist")
    }

    if(user.isEmailVerified){
        throw new ApiError(409 , "Email is already verified")   
    }

    const { unHashedToken , hashedToken , tokenExpiry } = user.generateTemporaryToken()
    user.emailVerificationToken = hashedToken
    user.emailVerificationExpiry = tokenExpiry

    await user.save({validateBeforeSave: false})

    //now send the email.
    await sendEmail(
        {
            email: user?.email,
            subject: "Please verify your email.",
            mailGenContent: emailVerifcationMailGenContent(
                user.username,
                `${req.protocol}://${req.get("host")}/api/v1/users/verify-email/${unHashedToken}`
            )
        }
    )

    return res
        .status(200)
        .json(
            new ApiResponse(
                200,
                {},
                "Mail has been sent to your email ID"
            )
        )

})

const refreshAccessToken = asyncHandler(async (req , res) => {
    const incomingRefreshToken = req.cookies.refreshToken || req.body.refreshToken

    if(!incomingRefreshToken){
        throw new ApiError(401,"Unauthorized access")
    }

    try {
        const decodedToken = jwt.verify(incomingRefreshToken, process.env.REFRESH_TOKEN_SECRET)

        const user = await User.findById(decodedToken?._id)
        if(!user){
            throw new ApiError(401, "Invalid refresh token")
        }

        if(incomingRefreshToken !== user?.refreshToken){
            throw new ApiError(401, "Refresh Token expired")
        }

        const options = {
            httpOnly: true,
            secure: true
        }

        const {accessToken, refreshToken: newRefreshToken} = await generateAccessAndRefreshTokens(user._id)

        user.refreshToken = newRefreshToken
        await user.save()

        return res  
            .status(200)
            .cookie("accessToken", accessToken , options)
            .cookie("refreshToken", newRefreshToken, options)
            .json(
                new ApiResponse(
                    200,
                    {accessToken, refreshToken:newRefreshToken},
                    "Access Token refreshed"
                )
            )

    } catch (error) {
        throw new ApiError(401, "Invalid refresh Token")
    }
})

const forgotPasswordRequest = asyncHandler(async (req , res) => {
    const {email} = req.body
    const user = await User.findOne({email})

    if(!user){
        throw new ApiError(
            404,
            "User does not exist",
            []            
        )
    }

    const {unHashedToken, hashedToken ,tokenExpiry} = user.generateTemporaryToken();

    user.forgotPasswordToken = hashedToken
    user.forgotPasswordExpiry = tokenExpiry

    await user.save({validateBeforeSave:false})

    await sendEmail(
        {
            email: user?.email,
            subject: "Password reset request",
            mailGenContent: forgotPasswordMailGenContent(
                user.username,
                `${process.env.FORGOT_PASSWORD_REDIRECT_URL}/$${unHashedToken}`,
            )
        }
    )

    return res  
        .status(200)
        .json(
            new ApiResponse(
                200,
                {},
                "Password reset mail has been sent on your email"
            )
        )

})

const resetForgotPasssword = asyncHandler(async (req , res) => {
    const {resetToken} = req.params
    const {newPassword} = req.body

    let hashedToken = crypto
        .createHash("sha256")
        .update(resetToken)
        .digest("hex")

    const user = await User.findOne({
        forgotPasswordToken: hashedToken,
        forgotPasswordExpiry: {$gt: Date.now()}
    })

    if(!user){
        throw new ApiError(489, "Token is invalid or expired")
    }

    user.forgotPasswordExpiry = undefined
    user.forgotPasswordToken = undefined

    user.password = newPassword

    await user.save({validateBeforeSave:false})

    return res
        .status(200)
        .json(
            new ApiResponse(200 ,
                {},
                "Password reset successfully"
            )
        )

})

const changeCurrentPassword = asyncHandler(async (req , res) => {
    const {oldPassword , newPassword} = req.body
    const user = await User.findById(req.user?._id)

    const isPasswordvalid = await user.isPasswordCorrect(oldPassword)

    if(!isPasswordvalid){
        throw new ApiError(
            400,
            "Inalid Password"
        )
    }

    user.password = newPassword;
    await user.save({validateBeforeSave:false})

    return res
        .status(200)
        .json(
            new ApiResponse(
                200,
                {},
                "Password changed successfully"
            )
        )
})

export { registerUser , login , logoutUser , getCurrentUser , verifyEmail , resendEmailVerification , refreshAccessToken , forgotPasswordRequest , resetForgotPasssword , changeCurrentPassword};

