import mongoose , { Schema } from "mongoose";
import bcrypt from "bcrypt";
import jwt from "jsonwebtoken";
import crypto from "crypto";

const userSchema = new Schema(
    {
        avatar: {
            type: {
                url: String,
                localpath: String,
            },//this type is object it means that mongoose will know that that avtar is object and it hase url and local path and both of them are strings..

            default: {
                url: `https://placehold.co/100x100`,
                localpath: ""
            }
        },
        username: {
            type: String,
            required: true, //it is prop of mongoDB
            unique: true,
            lowercase: true,
            trim: true,
            index: true
        },
        email: {
            type: String,
            required: true,
            unique: true,
            lowercase: true,
            trim: true
        },
        fullName: {
            type: String,
            trim: true
        },
        password: {
            type: String,
            required: [true,"Password is required"],
        },
        isEmailVerified: {
            type: Boolean,
            default: false,
        },
        refreshToken: {
            type: String,
        },
        forgotPasswordToken: {
            type: String
        },
        forgotPasswordExpiry: {
            type: Date
        },
        emailVerificationToken: {
            type: String
        },
        emailVerificationExpiry: {
            type: Date
        }
    },
    {
        timestamps: true,
    },
);


//Hooks (also called middleware) are functions that run
//BEFORE or AFTER certain Mongoose actions automatically.
userSchema.pre("save", async function () {
    if(!this.isModified("password")) return ;
    this.password = await bcrypt.hash(this.password,10);//since hashing can take sometime...
})

userSchema.methods.isPasswordCorrect = async function(password){
    return await bcrypt.compare(password,this.password);
};

userSchema.methods.generateAccessToken = function(){
    return jwt.sign(
        {
            _id: this._id,//this is this._id is automaticlly generated id my mongodb and we are using that..
            email: this.email,
            username: this.username
        },//this is payload

        //now provide the secret
        process.env.ACCESS_TOKEN_SECRET,

        //then provide expiry time
        {expiresIn: process.env.ACCESS_TOKEN_EXPIRY}
    )
}

userSchema.methods.generateRefreshToken = function(){
    return jwt.sign(
        {
            _id: this._id,
            email: this.email,
            username: this.username
            //email and usernmae doesnt need here....so doesnt matter if available or not
        },
        process.env.REFRESH_TOKEN_SECRET,
        {expiresIn: process.env.REFRESH_TOKEN_EXPIRY}
    )
}

userSchema.methods.generateTemporaryToken = function(){
    const unHashedToken = crypto.randomBytes(20).toString("hex");//crypto usually generates hex value..so we have to say that there is hexdecimal and then convert that to string..

    const hashedToken = crypto
        .createHash("sha256")
        .update(unHashedToken)
        .digest("hex")

    const tokenExpiry = Date.now() + (20*60*1000) // 20mins added
    return {unHashedToken,hashedToken,tokenExpiry}
}

const User = mongoose.model("User", userSchema);
export {User};

