class ApiError extends Error{
    constructor(
        statusCode,
        message = "Something went wrong",
        errors = [],
        stack = ""
    ){
        // If you add a constructor to a child class, you MUST initialize the parent class first using super() — one way or another.
        //since Error it self has own constructor and we made new for ApiError so.....
        //if we didn't make constructor for the ApiError then it will inherit themn from the Error..
        super(message)//call the parent class...will pass msg to error class of nodeJs
        this.statusCode = statusCode
        this.data = null
        this.message = message
        this.success = false
        this.errors = errors

// A stack trace tells you:
// WHERE the error happened
// WHICH functions were called
// in WHAT order

        if(stack){
            this.stack = stack
        } else {
            Error.captureStackTrace(this , this.constructor) // doubtfull
        }
    }
}

export { ApiError }

