const asyncHandler = (requestHandler) => {
  return (req, res, next) => {
    Promise.resolve(requestHandler(req, res, next)).catch((err) => next(err));

    //this promise line is same as
    /*
        try {
            await fn(req,res,next)
        } catch (err) {
             next(err)
            }

        */
  };
};

export { asyncHandler };

