import Mailgen from "mailgen"
import nodemailer from "nodemailer"

const sendEmail = async (options) => {
    const mailgenerator = new Mailgen({
        theme: "default",
        product: {
            name: "Task manager",
            link: "https://taskmanagerlink.com",
        },
    })

    const emailTextual = mailgenerator.generatePlaintext(
        options.mailGenContent
    )
    const emailHtml = mailgenerator.generate(options.mailGenContent)

    const transporter = nodemailer.createTransport({
        host: process.env.MAILTRAP_SMTP_HOST,
        port: Number(process.env.MAILTRAP_SMTP_PORT), // ✅ FIX (env → number)
        auth: {
            user: process.env.MAILTRAP_SMTP_USER,
            pass: process.env.MAILTRAP_SMTP_PASS,
        },
    })

    const mail = {
        from: "mail.taskmanager@example.com",
        to: options.email,          // ✅ this is CORRECT
        subject: options.subject,
        text: emailTextual,
        html: emailHtml,
    }

    try {
        await transporter.sendMail(mail) // ✅ Nodemailer uses `mail`
        console.log("Email sent successfully")
    } catch (error) {
        console.error("Email service failed")
        console.error("Error:", error)
    }
}

const emailVerifcationMailGenContent = (username, verificationURL) => {
    return {
        body: {
            name: username,
            intro: "Welcome to our app, we are excited to have you onboard",
            action: {
                instructions:
                    "To verify your email please click on the following button",
                button: {
                    color: "#22BC66",
                    text: "Verify your email",
                    link: verificationURL,
                },
            },
            outro: "Need help, or have questions? Just reply to this email",
        },
    }
}

const forgotPasswordMailGenContent = (username, passwordResetURL) => {
    return {
        body: {
            name: username,
            intro: "We got a request to reset your password",
            action: {
                instructions:
                    "To reset your password please click on the following button",
                button: {
                    color: "#42b373",
                    text: "Reset Password",
                    link: passwordResetURL,
                },
            },
            outro: "Need help, or have questions? Just reply to this email",
        },
    }
}

export {
    emailVerifcationMailGenContent,
    forgotPasswordMailGenContent,
    sendEmail,
}
